{
  "function": "review_plan",
  "parameter": {
    "plan_description": "Remediate OpenSC smart card drivers configuration by adding 'card_drivers = ;' to the app default block in /etc/opensc.conf. Steps: 1. Read current /etc/opensc.conf to locate app default block. 2. Use sed to insert line 'card_drivers = ;' inside the app default block. 3. Verify the change by reading back the file."
  }
}

{
  "remediationRemediationApplicable": false,
  "remediationApplies": "",
  "remediationScript": "# Remediation is applicable only in certain platforms if rpm --quiet -q kernel-core; then var_smartcard_drivers='' OPENSC_TOOL=\"/usr/bin/opensc-tool\" if [ -f \"${OPENSC_TOOL}\" ]; then ${OPENSC_TOOL} -S app:default:card_drivers:$var_smartcard_drivers fi else >&2 echo 'Remediation is not applicable, nothing was done' fi"
}
